    const $list = $('#vouchersTableFull');
    if (vouchers.length === 0) {
        $list.html('<div class="py-5 text-center text-muted"><i class="bi bi-wallet fs-1 mb-3"></i><p>No payment vouchers linked to this project.</p></div>');
